const touchpoints = $input.all().map(i => i.json);
if (!touchpoints.length) return { json: { error: 'No touchpoints found' } };

const firstTouch = touchpoints[0];
const lastTouch = touchpoints[touchpoints.length - 1];

const timeToConvert = Math.round((new Date(lastTouch.timestamp) - new Date(firstTouch.timestamp)) / 60000);

const channelsTouched = [...new Set(touchpoints.filter(t => t.source).map(t => {
  if (t.medium === 'ai_referral') return `${t.source} (AI)`;
  if (t.medium === 'email') return `${t.source} Email`;
  return `${t.source} (${t.medium || 'direct'})`;
}))];

return {
  json: {
    journey: touchpoints,
    first_touch: { source: firstTouch.source, medium: firstTouch.medium },
    time_to_convert_minutes: timeToConvert,
    total_touchpoints: touchpoints.length,
    channels_touched: channelsTouched,
    converted: touchpoints.some(t => t.event_type === 'purchase')
  }
};
